import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Theme Widgets","description":"Akurai Theme Widgets","frontmatter":{"title":"Theme Widgets","description":"Akurai Theme Widgets","weight":100,"extra":{"order":100},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/widgets"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/widgets"}],["meta",{"property":"og:title","content":"Theme Widgets"}],["meta",{"property":"og:description","content":"Akurai Theme Widgets"}],["meta",{"name":"twitter:title","content":"Theme Widgets"}],["meta",{"name":"twitter:description","content":"Akurai Theme Widgets"}]]},"headers":[],"relativePath":"docs/akurai/widgets.md","filePath":"docs/akurai/widgets.md"}'),o={name:"docs/akurai/widgets.md"};function d(r,e,n,g,c,l){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="akurai-widgets" tabindex="-1">Akurai Widgets <a class="header-anchor" href="#akurai-widgets" aria-label="Permalink to &quot;Akurai Widgets&quot;">​</a></h1><p>Akurai theme comes with built-in review widgets that you can use in page sidebars.</p><hr><h3 id="blocks-as-widget" tabindex="-1">Blocks as Widget <a class="header-anchor" href="#blocks-as-widget" aria-label="Permalink to &quot;Blocks as Widget&quot;">​</a></h3><p>Since WordPress 5.8 update, blocks can be used as widgets. The theme is updated so that you can use blocks in widget areas.</p><p>There&#39;s a new blocks category called <strong>Akurai Widgets</strong> that lets you add the same 2 block widgets: Single Review and Reviews List.</p><p>You can also use all review page blocks in review page sidebar.</p><blockquote><p>It is recommended to use blocks instead of legacy widgets, as they may not get updated in the future.</p></blockquote><hr><h2 id="using-widgets" tabindex="-1">Using Widgets <a class="header-anchor" href="#using-widgets" aria-label="Permalink to &quot;Using Widgets&quot;">​</a></h2><p>To add a widget to a sidebar or footer, in your WordPress dashboard visit <strong>Appearance</strong> → <strong>Widgets</strong>. Or you can use the Customizer as well, visit <strong>Appearance</strong> → <strong>Customize</strong> and select <strong>Widgets</strong>.</p><p>Besides the default WordPress widgets, 2 sportsbook widgets are available for you to use in sidebars and footer.</p><ul><li>Akurai Reviews Widget</li><li>Akurai Single Review Widget</li></ul><p>Check out the widgets on this <a href="https://demos.dinomatic.com/atlanta/page-templates/page-with-right-sidebar/" target="_blank" rel="noreferrer">demo page</a></p><h3 id="reviews-widget" tabindex="-1">Reviews Widget <a class="header-anchor" href="#reviews-widget" aria-label="Permalink to &quot;Reviews Widget&quot;">​</a></h3><p>Add the <code>Akurai Reviews Widget</code> to the widget area of your choice. Add a widget title, select whether to display the review terms of conditions or not, whether the logo image links the review page or the affiliate website, choose the reviews you want to display from the dropdown lists and click <code>Save</code>.</p><p>You can display up to 10 review.</p><h3 id="single-review-widget" tabindex="-1">Single Review Widget <a class="header-anchor" href="#single-review-widget" aria-label="Permalink to &quot;Single Review Widget&quot;">​</a></h3><p>Add the <code>Akurai Single Review Widget</code> to the widget area of your choice. Add a widget title, adjust settings: how to display terms and conditions and the review page link, choose the review you want to display from the dropdown list and click <code>Save</code>.</p>',19)])])}const p=t(o,[["render",d]]);export{u as __pageData,p as default};
